from config import COMPENSATION_REGLES, MILES_COMPENSATION, SEUIL_MODEREdef get_compensation(distance_km: float, retard_min: float) -> dict:    if retard_min < 180:        return {"eligible": False, "montant": 0, "motif": "Retard < 3h"}    montant = 0    for seg, r in COMPENSATION_REGLES.items():        lo, hi = r["distance"]        if lo <= distance_km < hi:            montant = r["montant"]; break    return {        "eligible": True,        "montant" : montant,        "motif"   : f"Retard ≥ 3h — Vol {'court' if distance_km<1500 else 'moyen/long'}-courrier",    }def get_crm_action(proba: float, distance: float) -> dict:    if proba >= 0.75:        return {"niveau":"Critique","action":"🚨 Compensation préventive + appel agent",                "message":"Votre vol présente un risque élevé de retard. Nous vous contactons en priorité.",                "canal":["SMS","Email","Appel agent"],"miles":MILES_COMPENSATION["Critique"],"priorité":1}    elif proba >= SEUIL_MODERE:        return {"niveau":"Élevé","action":"📧 Notification push + email proactif",                "message":"Votre vol pourrait subir un retard. Nous surveillons la situation.",                "canal":["Push notification","Email"],"miles":MILES_COMPENSATION["Élevé"],"priorité":2}    elif proba >= 0.25:        return {"niveau":"Modéré","action":"📩 Email d'information préventif",                "message":"Votre vol se déroule normalement. Nous restons attentifs.",                "canal":["Email"],"miles":MILES_COMPENSATION["Modéré"],"priorité":3}    else:        return {"niveau":"Faible","action":"✅ Aucune action requise",                "message":"Votre vol est prévu à l'heure. Bon voyage !",                "canal":[],"miles":0,"priorité":4}CHATBOT_INTENTS = {    "retard_probable" : ["retard","en retard","retardé","risque","delayed"],    "compensation"    : ["compensation","rembours","indemnité","argent","droits","ce 261"],    "miles"           : ["miles","points","fidélité","loyalty","bonus"],    "alternatives"    : ["alternative","autre vol","rebooking","replanifier"],    "contact"         : ["contact","appeler","agent","service client","aide"],    "bagage"          : ["bagage","valise","baggage","sac"],    "assurance"       : ["assurance","insurance","couvert","protection"],    "meteo"           : ["météo","meteo","weather","pluie","neige","vent"],}def detect_intent(msg: str) -> str:    msg_low = msg.lower()    scores  = {k: sum(kw in msg_low for kw in v) for k,v in CHATBOT_INTENTS.items()}    best    = max(scores, key=scores.get)    return best if scores[best] > 0 else "general"def generate_response(intent, proba=None, distance=1000, retard_estime=0, compagnie="votre compagnie") -> str:    rl = ("🔴 **risque critique**" if proba and proba>=0.75 else          "🟠 **risque élevé**"    if proba and proba>=0.50 else          "🟡 **risque modéré**"   if proba and proba>=0.25 else          "🟢 **faible risque**") if proba is not None else "**non évalué**"    if intent == "retard_probable":        if proba is None:            return "Je n'ai pas encore analysé votre vol. Rendez-vous dans **Prédiction** pour une estimation. ✈️"        action = get_crm_action(proba, distance)        return (f"D'après notre modèle, votre vol présente un {rl} "                f"(**{proba*100:.0f}%** de probabilité).\n\n💬 *{action['message']}*")    elif intent == "compensation":        comp = get_compensation(distance, retard_estime)        if not comp["eligible"]:            return (f"La compensation s'applique à partir de **3h de retard** (CE 261/2004).\n\n"                    f"Pour l'instant : {comp['motif']}. Des **miles préventifs** peuvent vous être offerts si votre vol présente un {rl}.")        return (f"Selon le règlement **CE 261/2004**, vous avez droit à **{comp['montant']} €**.\n\n"                f"📋 Motif : {comp['motif']}\n\nContactez {compagnie} ou une plateforme de réclamation en ligne.")    elif intent == "miles":        if proba and proba >= 0.25:            action = get_crm_action(proba, distance)            return (f"En raison du {rl}, {compagnie} vous offre **{action['miles']} miles** préventifs. 🎁\n\nCrédités sous 48h.")        return "Votre vol ne présente pas de risque particulier. Les miles sont attribués pour les vols à risque élevé. ✈️"    elif intent == "alternatives":        return ("Pour explorer des vols alternatifs :\n\n1. 📱 Connectez-vous à votre espace client\n"                "2. 🔄 Sélectionnez **'Modifier mon vol'**\n3. ☎️ Appelez le service client\n\n"                f"Avec un {rl}, nous recommandons d'anticiper dès maintenant.")    elif intent == "contact":        return (f"Notre service client est disponible 24h/24.\n\n📞 Téléphone | 💬 Chat live | 📧 Email\n\n"                f"Avec un {rl}, votre dossier sera traité en **priorité**.")    elif intent == "bagage":        return ("En cas de retard important :\n\n🧳 Vos bagages vous attendent à destination.\n"                "⚠️ Si correspondance manquée : signalez-le au comptoir de votre compagnie.\n"                "📋 Conservez tous vos reçus.")    elif intent == "assurance":        return ("Votre assurance voyage peut couvrir :\n\n✅ Hébergement (retard > 4h)\n"                "✅ Repas pendant l'attente\n✅ Frais de communication urgents\n\nVérifiez votre contrat.")    elif intent == "meteo":        return ("Les conditions météo sont intégrées dans notre modèle via les variables d'altitude "                "et la localisation GPS des aéroports.\n\nPour infos en temps réel : **Météo France** ☁️")    else:        return ("Je suis l'assistant IMSD. Je peux vous aider sur :\n\n"                "• 🎯 Risque de retard\n• 💰 Compensations CE 261/2004\n"                "• 🎁 Miles fidélité\n• 🔄 Alternatives de vol\n• ☎️ Contact service client\n\n"                "Que puis-je faire pour vous ?")